static int MapCheckCause(mapregion_t *map, int scause) {
  if (scause == 13 && (map->prot & PROT_READ) == 0)
    return ERR;
  if (scause == 15 && (map->prot & PROT_WRITE) == 0)
    return ERR;
  if (scause == 14 && (map->prot & PROT_EXEC) == 0)
    return ERR;
  return 0;
}

static uint64 UpdateFlag(mapregion_t* map){
  uint64 flags = PTE_U;
  if (map->prot & PROT_READ)
    flags |= PTE_R;
  if (map->prot & PROT_WRITE)
    flags |= PTE_W;
